ALTER TABLE `digital_products`
  ADD COLUMN `version` varchar(16) NOT NULL DEFAULT 'v1.0' AFTER `content`,
  ADD COLUMN `versionNumber` int NOT NULL DEFAULT 1 AFTER `version`,
  ADD COLUMN `isReleased` tinyint(1) NOT NULL DEFAULT 0 AFTER `versionNumber`,
  ADD COLUMN `isDraft` tinyint(1) NOT NULL DEFAULT 1 AFTER `isReleased`,
  ADD COLUMN `releasedAt` timestamp NULL AFTER `isDraft`,
  ADD COLUMN `changeNote` varchar(512) NULL AFTER `releasedAt`,
  ADD COLUMN `createdAt` timestamp NOT NULL DEFAULT (now()) AFTER `updatedBy`;

ALTER TABLE `digital_products` DROP INDEX `digital_products_productKey_unique`;

CREATE INDEX `idx_product_lang` ON `digital_products` (`productKey`, `lang`);
CREATE INDEX `idx_released` ON `digital_products` (`isReleased`);

